insert into ingredient_substitutions (
  ingredient_id, substitute_ingredient_id, confidence_score, substitution_type,
  replacement_ratio, recipe_category, notes, source_name, source_url, updated_at
)
select
  rows.ingredient_id, rows.substitute_ingredient_id, rows.confidence_score, rows.substitution_type,
  rows.replacement_ratio, rows.recipe_category, rows.notes, rows.source_name, rows.source_url, now()
from rows
where exists (select 1 from ingredients where ingredients.ingredient_id = rows.ingredient_id)
  and exists (select 1 from ingredients where ingredients.ingredient_id = rows.substitute_ingredient_id)
on conflict (ingredient_id, substitute_ingredient_id, recipe_category) do nothing;
